package qrspicmd

import (
	"bufio"
	"bytes"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"strings"
)

type sessionEntry struct {
	Type      string          `json:"type"`
	ID        string          `json:"id,omitempty"`
	Cwd       string          `json:"cwd,omitempty"`
	Timestamp string          `json:"timestamp,omitempty"`
	Message   *sessionMessage `json:"message,omitempty"`
}

type sessionMessage struct {
	Role         string          `json:"role"`
	Content      json.RawMessage `json:"content"`
	StopReason   string          `json:"stopReason,omitempty"`
	ErrorMessage string          `json:"errorMessage,omitempty"`
}

type AssistantTerminalEvidence struct {
	SessionPath        string `json:"sessionPath,omitempty"`
	SessionID          string `json:"sessionId,omitempty"`
	Line               int    `json:"line,omitempty"`
	Timestamp          string `json:"timestamp,omitempty"`
	StopReason         string `json:"stopReason,omitempty"`
	ErrorMessage       string `json:"errorMessage,omitempty"`
	ContextWindowError bool   `json:"contextWindowError,omitempty"`
	EvidenceID         string `json:"evidenceId,omitempty"`
}

type sessionContentBlock struct {
	Type string `json:"type"`
	Text string `json:"text,omitempty"`
}

func ResolveSessionPath(sessionDir, sessionID, cwd string) (string, error) {
	if strings.TrimSpace(sessionDir) == "" || strings.TrimSpace(sessionID) == "" {
		return "", errors.New("session dir and session id are required")
	}

	if _, err := os.Stat(sessionDir); err != nil {
		if os.IsNotExist(err) {
			return "", fmt.Errorf("session %q not found in %s", sessionID, sessionDir)
		}
		return "", err
	}

	var matches []string
	walkErr := filepath.WalkDir(
		sessionDir,
		func(path string, entry os.DirEntry, err error) error {
			if err != nil {
				return err
			}
			if entry.IsDir() || filepath.Ext(entry.Name()) != ".jsonl" {
				return nil
			}
			header, err := readSessionHeader(path)
			if err != nil {
				return nil
			}
			if header.Type == "session" && header.ID == sessionID &&
				(strings.TrimSpace(cwd) == "" || header.Cwd == cwd) {
				matches = append(matches, path)
			}
			return nil
		},
	)
	if walkErr != nil {
		return "", walkErr
	}

	switch len(matches) {
	case 1:
		return matches[0], nil
	case 0:
		return "", fmt.Errorf("session %q not found in %s", sessionID, sessionDir)
	default:
		return "", fmt.Errorf(
			"session %q matched multiple files in %s",
			sessionID,
			sessionDir,
		)
	}
}

func readSessionHeader(path string) (sessionEntry, error) {
	file, err := os.Open(path)
	if err != nil {
		return sessionEntry{}, err
	}
	defer file.Close()

	scanner := bufio.NewScanner(file)
	scanner.Buffer(make([]byte, 64*1024), 1024*1024)
	if !scanner.Scan() {
		if err := scanner.Err(); err != nil {
			return sessionEntry{}, err
		}
		return sessionEntry{}, errors.New("empty session file")
	}
	var header sessionEntry
	if err := json.Unmarshal(bytes.TrimSpace(scanner.Bytes()), &header); err != nil {
		return sessionEntry{}, err
	}
	return header, nil
}

func LatestAssistantTerminalEvidence(
	path string,
) (AssistantTerminalEvidence, bool, error) {
	file, err := os.Open(path)
	if err != nil {
		return AssistantTerminalEvidence{}, false, err
	}
	defer file.Close()

	sessionID := ""
	var latest AssistantTerminalEvidence
	found := false
	scanner := bufio.NewScanner(file)
	scanner.Buffer(make([]byte, 64*1024), 1024*1024)
	lineNo := 0
	for scanner.Scan() {
		lineNo++
		line := bytes.TrimSpace(scanner.Bytes())
		if len(line) == 0 {
			continue
		}
		var entry sessionEntry
		if err := json.Unmarshal(line, &entry); err != nil {
			continue
		}
		if entry.Type == "session" && strings.TrimSpace(entry.ID) != "" {
			sessionID = entry.ID
			continue
		}
		if entry.Type != "message" || entry.Message == nil ||
			entry.Message.Role != "assistant" {
			continue
		}
		if strings.TrimSpace(entry.Message.StopReason) == "" &&
			strings.TrimSpace(entry.Message.ErrorMessage) == "" {
			continue
		}
		evidence := AssistantTerminalEvidence{
			SessionPath:  path,
			SessionID:    sessionID,
			Line:         lineNo,
			Timestamp:    entry.Timestamp,
			StopReason:   entry.Message.StopReason,
			ErrorMessage: entry.Message.ErrorMessage,
		}
		evidence.ContextWindowError = strings.EqualFold(evidence.StopReason, "error") &&
			IsContextWindowErrorMessage(evidence.ErrorMessage)
		evidence.EvidenceID = terminalEvidenceID(evidence)
		latest = evidence
		found = true
	}
	if err := scanner.Err(); err != nil {
		return AssistantTerminalEvidence{}, false, err
	}
	return latest, found, nil
}

func IsContextWindowErrorMessage(message string) bool {
	text := strings.ToLower(message)
	needles := []string{
		"context window",
		"context length",
		"context_length_exceeded",
		"maximum context",
		"context limit",
		"input exceeds",
	}
	for _, needle := range needles {
		if strings.Contains(text, needle) {
			return true
		}
	}
	return false
}

func terminalEvidenceID(e AssistantTerminalEvidence) string {
	raw := strings.Join([]string{
		strings.TrimSpace(e.SessionID),
		filepath.Clean(strings.TrimSpace(e.SessionPath)),
		fmt.Sprintf("%d", e.Line),
		strings.TrimSpace(e.Timestamp),
		strings.TrimSpace(e.StopReason),
		strings.TrimSpace(e.ErrorMessage),
	}, "\x00")
	sum := sha256.Sum256([]byte(raw))
	return hex.EncodeToString(sum[:])[:16]
}

func ExtractFinalAssistantTextFromSession(path string) (string, error) {
	last, err := extractLastAssistantTextFromSession(path, true)
	if err != nil {
		return "", err
	}
	if last == "" {
		return "", fmt.Errorf(
			"session %s has no assistant text containing qrspi_result",
			path,
		)
	}
	return last, nil
}

func ExtractLastAssistantTextFromSession(path string) (string, error) {
	last, err := extractLastAssistantTextFromSession(path, false)
	if err != nil {
		return "", err
	}
	if last == "" {
		return "", fmt.Errorf("session %s has no assistant text", path)
	}
	return last, nil
}

func extractLastAssistantTextFromSession(
	path string,
	requireQRSPIResult bool,
) (string, error) {
	file, err := os.Open(path)
	if err != nil {
		return "", err
	}
	defer file.Close()

	var last string
	scanner := bufio.NewScanner(file)
	scanner.Buffer(make([]byte, 64*1024), 1024*1024)
	for scanner.Scan() {
		line := bytes.TrimSpace(scanner.Bytes())
		if len(line) == 0 {
			continue
		}
		var entry sessionEntry
		if err := json.Unmarshal(line, &entry); err != nil {
			continue
		}
		if entry.Type != "message" || entry.Message == nil ||
			entry.Message.Role != "assistant" {
			continue
		}
		if requireQRSPIResult &&
			(entry.Message.StopReason == "error" || entry.Message.StopReason == "aborted") {
			continue
		}
		text := textBlocksFromAssistantMessage(*entry.Message)
		if strings.TrimSpace(text) == "" {
			continue
		}
		if !requireQRSPIResult || strings.Contains(text, "qrspi_result") {
			last = text
		}
	}
	if err := scanner.Err(); err != nil {
		return "", err
	}
	return last, nil
}

func textBlocksFromAssistantMessage(msg sessionMessage) string {
	var blocks []sessionContentBlock
	if err := json.Unmarshal(msg.Content, &blocks); err == nil {
		var parts []string
		for _, block := range blocks {
			if block.Type == "text" && block.Text != "" {
				parts = append(parts, block.Text)
			}
		}
		return strings.Join(parts, "\n")
	}

	var text string
	if err := json.Unmarshal(msg.Content, &text); err == nil {
		return text
	}
	return ""
}

func RunContinue(ctx context.Context, opts ContinueOptions, d deps, out io.Writer) error {
	if strings.TrimSpace(opts.StateFile) == "" {
		return errors.New("state-file is required")
	}
	out = ensureWriter(out)
	clock := d.Clock
	if clock == nil {
		clock = time.Now
	}
	store := stateStore(d, "", clock)
	state, err := store.Load(opts.StateFile)
	if err != nil {
		return err
	}
	if piModel := strings.TrimSpace(opts.PiModel); piModel != "" {
		state.PiModel = piModel
		if err := store.Save(opts.StateFile, state); err != nil {
			return err
		}
	}
	if strings.TrimSpace(opts.PlanDir) == "" {
		opts.PlanDir = state.CanonicalPlanDir
	}
	if strings.TrimSpace(opts.PlanDir) == "" {
		return errors.New("plan-dir is required")
	}
	if state.ActiveChild == nil {
		card := buildContinueActionCard(
			state,
			opts,
			errors.New("no active child to continue"),
		)
		state.LastActionCard = card
		_ = store.Save(opts.StateFile, state)
		if card != nil {
			return writeManagerActionCard(out, *card, opts.Output)
		}
		return errors.New("no active child to continue")
	}
	if strings.TrimSpace(opts.Stage) == "" {
		opts.Stage = state.ActiveChild.Stage
	}
	if strings.TrimSpace(opts.Stage) == "" {
		return errors.New("stage is required")
	}
	health, healthErr := InspectActiveChildHealth(ctx, state, opts.StateFile, d)
	if healthErr != nil {
		return healthErr
	}
	if IsRecoverableNoResultChild(health) {
		card := BuildChildContextExhaustedCard(health, state, opts.StateFile)
		if card != nil {
			state.LastActionCard = card
			_ = store.Save(opts.StateFile, state)
			return writeManagerActionCard(out, *card, opts.Output)
		}
	}
	if IsTerminalFailedChild(health) {
		card := BuildChildLaunchFailedCard(health, state, opts.StateFile)
		if card != nil {
			state.LastActionCard = card
			_ = store.Save(opts.StateFile, state)
			return writeManagerActionCard(out, *card, opts.Output)
		}
	}

	result := ContinueResult{}
	parsed, err := validateActiveChild(ctx, state, opts)
	if err != nil {
		if shouldRepromptAfterValidationError(state, opts, err) {
			if repromptErr := continueReprompt(
				ctx,
				state,
				opts,
				d,
				out,
				err,
			); repromptErr != nil {
				return repromptErr
			}
			result.Reprompted = true
			result.StopReason = "invalid result; reprompted active child"
			return writeContinueOutput(out, opts, result)
		}
		if isRetryExhaustedValidationError(state, opts, err) {
			result.StopReason = err.Error()
			card := buildContinueActionCard(state, opts, err)
			if card != nil {
				state.LastActionCard = card
				_ = store.Save(opts.StateFile, state)
			}
			return writeRetryExhaustedNotice(out, opts, state, err)
		}
		card := buildContinueActionCard(state, opts, err)
		if card != nil {
			state.LastActionCard = card
			_ = store.Save(opts.StateFile, state)
			return writeManagerActionCard(out, *card, opts.Output)
		}
		return err
	}
	result.Validated = &parsed
	result.PrimaryArtifact = parsed.Result.PrimaryArtifact

	nextState, err := decideValidatedResult(ctx, state, parsed, opts, store)
	if err != nil {
		return err
	}
	result.Decided = true
	result.NextNodeID = parsed.Decision.NextNodeID
	result.Policy = activePolicySummary(nextState)
	result.NextChild = nextChildInfo(nextState, parsed.Decision.NextNodeID)
	result.WaitingHuman = parsed.Decision.WaitingHuman
	result.StopReason = parsed.Decision.StopReason
	if result.WaitingHuman {
		result.HumanPrompt = humanPromptContext(state, opts.StateFile, parsed)
		card := humanGateActionCard(state, opts.StateFile, result.HumanPrompt)
		result.ActionCard = &card
		nextState.LastActionCard = &card
		_ = store.Save(opts.StateFile, nextState)
	}

	if parsed.Decision.StartNext {
		launched, err := startNextChildFromDecision(
			ctx,
			nextState,
			parsed.Decision,
			opts,
			d,
			out,
		)
		if err != nil {
			return err
		}
		launched, _, err = maybeStartManagerCompaction(
			ctx,
			launched,
			opts.StateFile,
			opts.Usage,
			d,
			out,
		)
		if err != nil {
			return err
		}
		result.StartedChild = launched.ActiveChild
	}
	return writeContinueOutput(out, opts, result)
}

func BuildChildContextExhaustedCard(
	health ActiveChildHealth,
	state ManagerState,
	stateFile string,
) *ManagerActionCard {
	if health.Status != ActiveChildContextExhausted {
		return nil
	}
	evidence := []string{
		fmt.Sprintf(
			"child: %s stage=%s",
			health.ChildID,
			firstNonEmpty(health.Stage, string(state.Workflow.CurrentNodeID)),
		),
		fmt.Sprintf("session: %s", firstNonEmpty(health.SessionPath, health.SessionDir)),
		fmt.Sprintf("status: %s", health.Status),
	}
	evidence = append(evidence, health.Evidence...)
	for _, line := range health.OutputTail {
		evidence = append(evidence, "output tail: "+line)
	}
	return &ManagerActionCard{
		Kind:              ActionChildContextExhausted,
		Severity:          "warning",
		Summary:           "child ended without valid qrspi_result after context-limit evidence",
		Evidence:          evidence,
		RecommendedAction: "resume the same child and compact only if context-limit evidence is real; otherwise validate/rebind latest session or relaunch the same graph node",
		SafeCommand: fmt.Sprintf(
			"vamos qrspi inspect --state-file %s --sessions --latest",
			stateFile,
		),
		ContinueCommand: fmt.Sprintf(
			"vamos qrspi recover-manual --state-file %s --mode latest-session --continue",
			stateFile,
		),
		RequiresHuman: false,
	}
}

